INSERT INTO `rb_advogados` (`id`, `created_at`, `nome`, `socio`, `curriculum`) VALUES (1,'2013-06-25 21:46:18','Gustavo Passarelli da Silva',1,'<p>Advogado com atua&ccedil;&atilde;o na &aacute;rea de direito contratual, empresarial e societ&aacute;rio, com experi&ecirc;ncia na &aacute;rea de contencioso e consultoria jur&iacute;dica. Graduado em Direito pela Universidade Cat&oacute;lica Dom Bosco (UCDB), 1997. Especialista em Direito Processual Civil pelo Instituto Nacional de P&oacute;s-Gradua&ccedil;&atilde;o, Mestre em Direito e Economia pela Universidade Gama Filho (UGF-RJ), Doutorando em Direito Civil pela Universidad de Buenos Aires (UBA). Larga experi&ecirc;ncia em doc&ecirc;ncia nas &aacute;reas de direito processual civil, direito contratual e responsabilidade civil e sucess&atilde;o familiar (aspectos jur&iacute;dicos), em cursos de gradua&ccedil;&atilde;o e p&oacute;s-gradua&ccedil;&atilde;o na Universidade Cat&oacute;lica Dom Bosco, Universidade Anhanguera, Escola da Magistratura, ENFAM (Escola Nacional de Forma&ccedil;&atilde;o de Magistrados), ESUD (Escola Superior de Direito) FGV (Funda&ccedil;&atilde;o Get&uacute;lio Vargas), Universidade Federal de Mato Grosso do Sul, Escola Superior do Minist&eacute;rio P&uacute;blico do Mato Grosso do Sul (ESPME), Escola da Magistratura do Trabalho (EMATRA) e Faculdade de Economia e Administra&ccedil;&atilde;o da Universidade de S&atilde;o Paulo (FEA-USP), Diretor-Geral da Escola Superior da Advocacia (ESA-MS) no per&iacute;odo de 2010-2013, Conselheiro Federal Suplente OAB-MS, integrante da Comiss&atilde;o sobre a Quest&atilde;o Ind&iacute;gena no Mato Grosso do Sul - CNJ (Conselho Nacional de Justi&ccedil;a), com diversos artigos cient&iacute;ficos publicados em revistas e sites especializados, participa&ccedil;&atilde;o em diversos eventos jur&iacute;dicos na qualidade de conferencista e debatedor. Nomeado Conselheiro do Tribunal Administrativo Tribut&aacute;rio do Estado de Mato Grosso do Sul - TAT - MS, representando a FAMASUL, 2015.&nbsp;<strong><br /></strong></p>\r\n<p><strong>&nbsp;&nbsp;</strong></p>'),
(3,'2013-06-27 17:47:16','Juliana Miranda Rodrigues da Cunha Passarelli',1,'<p style=\"text-align: justify;\">Advogada com larga experi&ecirc;ncia na &aacute;rea de direito p&uacute;blico, contratual e empresarial, com atua&ccedil;&atilde;o no contencioso e consultoria jur&iacute;dica. Graduada em Direito pela Universidade Cat&oacute;lica Dom Bosco (UCDB), 2001. P&oacute;s-graduada em Direito Civil e Processual Civil pela Universidade para o Desenvolvimento do Estado e Regi&atilde;o do Pantanal (UNIDERP), 2005. Diversos cursos realizados na &aacute;rea de direito administrativo, gest&atilde;o de contratos administrativos, licita&ccedil;&otilde;es e legaliza&ccedil;&atilde;o do patrim&ocirc;nio p&uacute;blico. Experi&ecirc;ncia na advocacia p&uacute;blica como gerente jur&iacute;dica e licita&ccedil;&otilde;es em sociedade de economia mista, bem como privada mediante atua&ccedil;&atilde;o tanto no contencioso quanto consultivo.</p>'),
(46,'2019-08-13 21:07:25','Claudio de Rosa Guimarães',0,'<p>Cl&aacute;udio de Rosa Guimar&atilde;es, &eacute; advogado e professor universit&aacute;rio.<br />Formou-se pela Universidade do Oeste Paulista na turma de 1996 estando inscrito na OAB/MS sob o n&uacute;mero 7.620. Especializou-se em Direito Processual Civil e Direito Civil pelo Instituto Nacional de P&oacute;s-Gradua&ccedil;&atilde;o - INPG no per&iacute;odo compreendido entre 2002/2003. Em 2.009 ingressou no programa de mestrado em desenvolvimento local da Universidade Cat&oacute;lica Dom Bosco e em fevereiro de 2012 obteve o t&iacute;tulo de Mestre. &Eacute; professor titular da cadeira de Direito Civil da Universidade Cat&oacute;lica Dom Bosco, desde o ano de 2003.</p>'),
(67,'2023-09-01 20:19:28','Nathan Felipe Costa de Oliveira',0,''),
(61,'2022-11-22 14:48:04','Taynara Gomes de Almeida',0,'<p>Graduada em Direito pela Universidade Anhanguera UNIDERP (2017), P&oacute;s-graduanda em Planejamento Tribut&aacute;rio e&nbsp; P&oacute;s-Graduanda em Tribunal do J&uacute;ri e Execu&ccedil;&atilde;o Criminal, ambos pela Faculdade Legale.</p>');
