INSERT INTO `rb_areas-atuacao` (`id`, `created_at`, `titulo`, `resumo`, `texto`, `ativo`, `ordem`) VALUES (1,'2013-06-25 22:07:18','Direito Empresarial e Societário','É relacionado ao estudo das sociedades empresárias.','<p>Ligado &agrave;s quest&otilde;es que digam respeito aos s&oacute;cios e acionistas destas pessoas jur&iacute;dicas e as diversas situa&ccedil;&otilde;es que possam ocorrer no seu seio, como altera&ccedil;&otilde;es de controle e de participa&ccedil;&atilde;o, quest&otilde;es gerenciais, conflitos societ&aacute;rios e outros fen&ocirc;menos.</p>',1,2),
(2,'2013-06-27 17:50:32','Direito Civil','O direito civil é o principal ramo do direito privado.','<p style=\"text-align: justify;\">Trata-se do conjunto de normas (regras e princ&iacute;pios) que regulam as rela&ccedil;&otilde;es entre os particulares, que comumente encontram-se em uma situa&ccedil;&atilde;o de equil&iacute;brio de condi&ccedil;&otilde;es. O direito civil &eacute; o direito do dia a dia das pessoas, em suas rela&ccedil;&otilde;es privadas cotidianas.&nbsp;</p>',1,1),
(3,'2013-06-27 17:52:19','Direito do Consumidor','Lida com conflitos de consumo e com a defesa dos direitos dos consumidores.','<p>Se encontra desenvolvido na maior parte dos pa&iacute;ses com sociedades de consumo e sistemas legais funcionais.</p>',1,3),
(4,'2013-08-09 18:18:46','Direito Trabalhista','Conjunto de normas jurídicas que regem as relações entre empregados e empregadores.','<p>S&atilde;o os direitos resultantes da condi&ccedil;&atilde;o jur&iacute;dica dos trabalhadores. Estas normas, no Brasil, est&atilde;o regidas pela Consolida&ccedil;&atilde;o das Leis do Trabalho (CLT), Constitui&ccedil;&atilde;o Federal de 1988 e v&aacute;rias leis esparsas (como a lei que define o trabalho do estagi&aacute;rio, dentre outras).</p>',1,4),
(5,'2013-08-09 18:19:02','Direito Administrativo e Constitucional','Conjunto harmônico de princípios jurídicos que regem os órgãos, os agentes, as atividades públicas tendentes a realizar concreta, direta e imediatamente os fins desejados pelo Estado.','<p style=\"text-align: justify;\">Os princ&iacute;pios constitucionais do &acirc;mbito administrativo visam dar credibilidade ao ato administrativo praticado pelo gestor da administra&ccedil;&atilde;o p&uacute;blica, seja pelo cumprimento da lei; obedecendo a publicidade e moralidade, mais sempre buscando a efici&ecirc;ncia do bom servi&ccedil;o p&uacute;blico, e praticando-o sempre de modo impessoal, buscando t&atilde;o somente prestar o servi&ccedil;o p&uacute;blico em prol dos administrados.</p>',1,5),
(6,'2013-08-09 18:19:19','Direito Ambiental','Constitui um conjunto de princípios jurídicos e de normas jurídicas voltado à proteção jurídica da qualidade do meio ambiente.','<p>Trata-se de um direito \"transversal\" ou \"horizontal\", que tem por base as teorias geopol&iacute;ticas ou de pol&iacute;tica ambiental transpostas em leis espec&iacute;ficas, pois abrange todos os ramos do direito, estando intimamente relacionado com o direito constitucional, direito administrativo, direito civil, direito penal, direito processual e direito do trabalho.</p>',1,6),
(7,'2013-08-09 18:20:38','Planejamento Sucessório','Estabelece estruturas com a finalidade de proporcionar maior aparato jurídico à partilha do patrimônio familiar, de maneira menos dispendiosa e evitando, quando possível, o processo judicial.','<p>Uma ferramenta cada vez mais utilizada para permitir a estrutura&ccedil;&atilde;o do patrim&ocirc;nio familiar e garantir, assim, sua perpetua&ccedil;&atilde;o, uma vez que possibilita o pleno funcionamento e continuidade dos neg&oacute;cios, mesmo na hip&oacute;tese de aus&ecirc;ncia de membros do grupo.&nbsp;</p>',1,7);
