INSERT INTO `rb_paginas` (`id`, `titulo`, `texto`, `resumo`, `description`, `keywords`, `temtexto`, `temresumo`, `temimagem`, `temmeta`, `visivel`) VALUES (100,'Notícias','<p>As &uacute;ltimas not&iacute;cias s&atilde;o publicadas neste campo para fomentar questionamentos atuais sobre assuntos relacionados &agrave; &aacute;rea do Direito.&nbsp;</p>',NULL,'','',1,0,0,1,1),
(101,'O Escritório','<p style=\"text-align: justify;\">O escrit&oacute;rio tem como pol&iacute;tica de atua&ccedil;&atilde;o, lidar com a diversidade de forma individual, analisando e identificando as necessidades de cada um de seus clientes, sempre com o comprometimento necess&aacute;rio para solucionar toda e qualquer demanda.</p>\r\n<p style=\"text-align: justify;\">Desde 2005 realiza a presta&ccedil;&atilde;o de assessoria jur&iacute;dica com alto padr&atilde;o de qualidade, visando &agrave; preocupa&ccedil;&atilde;o em assessorar os clientes com seriedade e compet&ecirc;ncia para dar efetividade, e garantindo dessa forma, os direitos nas leis e nos fatos.</p>\r\n<p style=\"text-align: justify;\">Advogados gabaritados em diversas &aacute;reas integram experi&ecirc;ncia em sua trajet&oacute;ria, bem como precis&atilde;o t&eacute;cnica, foco local e vis&atilde;o global em cada trabalho. O escrit&oacute;rio constr&oacute;i a cada dia valores &eacute;ticos e preza por uma conduta de acordo com a verdade, atuando com franqueza e transpar&ecirc;ncia.</p>',NULL,'','',1,0,1,1,1),
(102,'ADVOGADOS','<p style=\"text-align: justify;\">Profissionais que pautam suas condutas pelos elevados valores de honestidade, verdade e justi&ccedil;a, aceitando o desafio de oferecer solu&ccedil;&otilde;es jur&iacute;dicas inovadoras, respeitando as tradi&ccedil;&otilde;es legais e os princ&iacute;pios &eacute;ticos.</p>',NULL,'','',1,0,0,1,1),
(103,'Áreas de Atuação','<p style=\"text-align: justify;\">Nosso escrit&oacute;rio oferece todas as diretrizes jur&iacute;dicas necess&aacute;rias para que os profissionais com conhecimentos t&eacute;cnicos estejam prontos para atender as demandas de cada cliente. Em todas estas &aacute;reas nossa atua&ccedil;&atilde;o atende ao consultivo e consultivo preventivo, contencioso e contratual.</p>',NULL,'','',1,0,0,1,1),
(104,'Artigos','<p>Artigos relacionados &agrave;s diversas &aacute;reas do Direito s&atilde;o disponibilizados para os nossos clientes&nbsp; com o intuito de mostrar quest&otilde;es espec&iacute;ficas do &acirc;mbito jur&iacute;dico.&nbsp;</p>',NULL,'','',1,0,0,1,1),
(105,'Carreira','<p>Quer ingressar na carreira jur&iacute;dica? Preencha os campos abaixo corretamente com a fun&ccedil;&atilde;o desejada para que possamos entrar em contato.&nbsp;</p>',NULL,'','',1,0,0,1,1),
(106,'Contato',NULL,NULL,'','',0,0,1,1,1);
